solution:
def merge(A, B):
    i = j = 0
    out = []
    while i < len(A) and j < len(B):
        if A[i] <= B[j]:
            out.append(A[i])
            i += 1
        else:
            out.append(B[j])
            j += 1
    out += A[i:]
    out += B[j:]
    return out

